Building a Python FastAPI REST API.

```txt title="requirements.txt"
fastapi>=0.111.0
uvicorn[standard]>=0.30.0
pydantic>=2.7.0
```

```python title="main.py"
from fastapi import FastAPI, HTTPException
from fastapi.middleware.cors import CORSMiddleware
from pydantic import BaseModel
from typing import Optional
import uuid

app = FastAPI(title="Inventory API", version="1.0.0")

app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_methods=["*"],
    allow_headers=["*"],
)

# In-memory store (replace with database)
items: dict[str, dict] = {}

class Item(BaseModel):
    name: str
    description: Optional[str] = None
    price: float
    in_stock: bool = True

class ItemUpdate(BaseModel):
    name: Optional[str] = None
    description: Optional[str] = None
    price: Optional[float] = None
    in_stock: Optional[bool] = None

@app.get("/health")
def health():
    return {"status": "ok", "items": len(items)}

@app.get("/items")
def list_items():
    return {"items": list(items.values()), "total": len(items)}

@app.get("/items/{item_id}")
def get_item(item_id: str):
    item = items.get(item_id)
    if not item:
        raise HTTPException(status_code=404, detail="Item not found")
    return item

@app.post("/items", status_code=201)
def create_item(item: Item):
    item_id = str(uuid.uuid4())
    record = {"id": item_id, **item.model_dump()}
    items[item_id] = record
    return record

@app.put("/items/{item_id}")
@app.patch("/items/{item_id}")
def update_item(item_id: str, update: ItemUpdate):
    item = items.get(item_id)
    if not item:
        raise HTTPException(status_code=404, detail="Item not found")
    for field, val in update.model_dump(exclude_none=True).items():
        item[field] = val
    return item

@app.delete("/items/{item_id}", status_code=204)
def delete_item(item_id: str):
    if item_id not in items:
        raise HTTPException(status_code=404, detail="Item not found")
    del items[item_id]
```

